// FILTER & PROCESS: All My Account Tweets (Dynamic)
const inputData = $input.all();
const processed = [];
const myAccounts = $('Session Config').item.json.myAccounts || [];
const accountLookup = {};
myAccounts.forEach(a => { accountLookup[a.username.toLowerCase()] = a.accountTag; });

function calculateCompositeScore(text, views, bookmarks, retweets, quotes, likes, replies) {
  const textLower = text.toLowerCase();
  const ctaPhrases = ['comment','reply','dm me','drop a','let me know','type','say "', "say '", 'tell me','share your','follow','retweet','rt this','must be following',"i'll send","and i'll",'required'];
  const hasCTA = ctaPhrases.some(p => textLower.includes(p));
  const replyToLikeRatio = likes > 0 ? replies / likes : 0;
  const likelyCTA = replyToLikeRatio > 0.5;
  const isCTAPost = hasCTA || likelyCTA;
  const BW=5, RTW=4, QW=3, LW=isCTAPost?1:2, RW=isCTAPost?2:1;
  const we = (bookmarks*BW)+(retweets*RTW)+(quotes*QW)+(likes*LW)+(replies*RW);
  const er = (we / Math.max(views,1)) * 100;
  const rawScore = Math.min(Math.log10(er + 1) * 30, 100);
  return { score: parseFloat(rawScore.toFixed(1)), isCTAPost };
}

inputData.forEach(item => {
  let tweets = Array.isArray(item.json) ? item.json : (item.json?.data || [item.json]);
  tweets.forEach(tweet => {
    if (!tweet || tweet.isRetweet || tweet.isReply) return;
    const text = tweet.text || '';
    if (text.length < 20) return;
    const author = typeof tweet.author === 'string' ? tweet.author : (tweet.author?.userName || 'unknown');
    const tweetId = tweet.id || tweet.url?.split('/').pop();
    if (!tweetId) return;
    const views=tweet.viewCount||0, likes=tweet.likeCount||0, retweets=tweet.retweetCount||0;
    const replies=tweet.replyCount||0, quotes=tweet.quoteCount||0, bookmarks=tweet.bookmarkCount||0;
    const totalEngagement = likes+retweets+replies+quotes+bookmarks;
    const textLower = text.toLowerCase();
    const scoreData = calculateCompositeScore(text, views, bookmarks, retweets, quotes, likes, replies);
    let contentType = 'value';
    if (textLower.includes('automation') || textLower.includes('workflow') || textLower.includes('n8n')) contentType = 'automation';
    const account = accountLookup[author.toLowerCase()] || 'unknownTweets';
    const isThread = text.includes('\ud83e\uddf5') || /\d+\/\d+/.test(text);
    processed.push({ json: {
      tweetId, text, account,
      url: tweet.url || `https://twitter.com/${author}/status/${tweetId}`,
      createdAt: tweet.createdAt,
      collectedAt: new Date().toISOString(),
      viewCount: views, likeCount: likes, retweetCount: retweets,
      replyCount: replies, quoteCount: quotes, bookmarkCount: bookmarks,
      totalEngagement, compositeScore: scoreData.score, isCTAPost: scoreData.isCTAPost,
      hook: text.substring(0, 120), contentType,
      formatType: isThread ? 'thread' : 'tweet',
      isViralPattern: views >= 50000 || scoreData.score >= 50,
      mediaUrls: tweet.media?.map(m => m.url).filter(Boolean).join(', ') || ''
    }});
  });
});
console.log(`My Account Tweets: Processed ${processed.length} tweets from ${myAccounts.length} accounts`);
return processed;

// FILTER & PROCESS: Tracked Accounts Tweets
const inputData = $input.all();
const processed = [];
let skippedIrrelevant = 0;
const trackedAccountsMeta = {};
const taWithMeta = $('Session Config').item.json.trackedAccountsWithMeta || [];
taWithMeta.forEach(a => { trackedAccountsMeta[a.username.toLowerCase()] = a; });

const nicheKeywords = ['ai','artificial intelligence','machine learning','ml','llm','gpt','claude','opus','sonnet','gemini','openai','anthropic','chatgpt','copilot','codex','grok','perplexity','midjourney','stable diffusion','deep learning','neural','transformer','fine-tune','fine tune','embedding','vector','rag','prompt','token','inference','automat','workflow','n8n','zapier','make.com','integromat','no-code','nocode','low-code','lowcode','api','webhook','pipeline','scrape','scraping','bot','cron','agent','agentic','multi-agent','autonomous','openclaw','open claw','mcp','tool use','function call','saas','startup','founder','indie hack','solopreneur','bootstrap','ship','shipped','shipping','build','deploy','launch','revenue','mrr','arr','monetiz','pricing','vibe cod','cursor','replit','v0','bolt','content','creator','audience','growth','engagement','twitter','x.com','thread','newsletter','code','coding','developer','programming','software','engineer','open source','github','npm','python','javascript','typescript','react','node','docker','cloud','aws','server','vps','replac','disrupt','obsolete','commodit','future of','age of ai','workforce'];

function isNicheRelevant(text) { const tl = text.toLowerCase(); return nicheKeywords.some(kw => tl.includes(kw)); }

function calculateCompositeScore(text, views, bookmarks, retweets, quotes, likes, replies) {
  const textLower = text.toLowerCase();
  const ctaPhrases = ['comment','reply','dm me','drop a','let me know','type','say "', "say '", 'tell me','share your','follow','retweet','rt this','must be following',"i'll send","and i'll",'required'];
  const hasCTA = ctaPhrases.some(p => textLower.includes(p));
  const likelyCTA = likes > 0 ? replies/likes > 0.5 : false;
  const isCTAPost = hasCTA || likelyCTA;
  const BW=5, RTW=4, QW=3, LW=isCTAPost?1:2, RW=isCTAPost?2:1;
  const we = (bookmarks*BW)+(retweets*RTW)+(quotes*QW)+(likes*LW)+(replies*RW);
  const rawScore = Math.min(Math.log10((we/Math.max(views,1))*100 + 1) * 30, 100);
  return { score: parseFloat(rawScore.toFixed(1)), isCTAPost };
}

inputData.forEach(item => {
  let tweets = Array.isArray(item.json) ? item.json : (item.json?.data || [item.json]);
  tweets.forEach(tweet => {
    if (!tweet || tweet.isRetweet || tweet.isReply) return;
    const text = tweet.text || '';
    if (text.length < 20) return;
    if (!isNicheRelevant(text)) { skippedIrrelevant++; return; }
    const author = typeof tweet.author === 'string' ? tweet.author : (tweet.author?.userName || 'unknown');
    const tweetId = tweet.id || tweet.url?.split('/').pop();
    if (!tweetId) return;
    const views=tweet.viewCount||0, likes=tweet.likeCount||0, retweets=tweet.retweetCount||0;
    const replies=tweet.replyCount||0, quotes=tweet.quoteCount||0, bookmarks=tweet.bookmarkCount||0;
    const totalEngagement = likes+retweets+replies+quotes+bookmarks;
    const scoreData = calculateCompositeScore(text, views, bookmarks, retweets, quotes, likes, replies);
    const textLower = text.toLowerCase();
    let contentType = 'value';
    if (textLower.includes('n8n') || textLower.includes('workflow') || textLower.includes('automat')) contentType = 'automation';
    else if (textLower.includes('agent') || textLower.includes('agentic')) contentType = 'agents';
    else if (textLower.includes('api') || textLower.includes('code') || textLower.includes('deploy')) contentType = 'technical';
    else if (textLower.includes('saas') || textLower.includes('startup') || textLower.includes('revenue')) contentType = 'business';
    const accountMeta = trackedAccountsMeta[author.toLowerCase()] || {};
    const isThread = text.includes('\ud83e\uddf5') || /\d+\/\d+/.test(text);
    processed.push({ json: {
      tweetId, text, author,
      url: tweet.url || `https://twitter.com/${author}/status/${tweetId}`,
      createdAt: tweet.createdAt, collectedAt: new Date().toISOString(),
      viewCount: views, likeCount: likes, retweetCount: retweets,
      replyCount: replies, quoteCount: quotes, bookmarkCount: bookmarks,
      totalEngagement, compositeScore: scoreData.score, isCTAPost: scoreData.isCTAPost,
      accountCategory: accountMeta.category || '', voiceAlignment: accountMeta.voiceAlignment || '',
      hook: text.substring(0, 120), contentType,
      formatType: isThread ? 'thread' : 'tweet',
      isViralPattern: views >= 50000 || scoreData.score >= 50,
      isThread: isThread,
      mediaUrls: tweet.media?.map(m => m.url).filter(Boolean).join(', ') || '',
      hashtags: (text.match(/#[\w]+/g) || []).join(', ')
    }});
  });
});
console.log(`Tracked Accounts: Processed ${processed.length} tweets, skipped ${skippedIrrelevant} off-topic`);
return processed;

// Summary Statistics for Telegram Notification (Dynamic Version)
const inputData = $input.all();

const stats = {
  totalTweets: inputData.length,
  byAccount: {},
  byStream: { myAccounts: 0, trackedAccounts: 0, viral: 0 },
  totalViews: 0,
  totalEngagement: 0,
  totalBookmarks: 0,
  avgCompositeScore: 0,
  topTweet: null,
  highestScore: 0
};

// Get my account tags for categorization
const myAccounts = $('Session Config').item.json.myAccounts || [];
const myAccountTagSet = new Set(myAccounts.map(a => a.accountTag));

let scoreSum = 0;
let scoreCount = 0;

inputData.forEach(item => {
  const tweet = item.json?.fields || item.json;
  if (!tweet) return;

  const views = tweet['View Count'] || tweet.viewCount || 0;
  const engagement = tweet['Total Engagement'] || tweet.totalEngagement || 0;
  const bookmarks = tweet['Bookmark Count'] || tweet.bookmarkCount || 0;
  const compositeScore = tweet['Composite Score'] || tweet.compositeScore || 0;
  const account = tweet.Account || tweet.account || 'Unknown';
  const author = tweet.Author || tweet.author || account;

  stats.totalViews += views;
  stats.totalEngagement += engagement;
  stats.totalBookmarks += bookmarks;

  if (compositeScore > 0) {
    scoreSum += compositeScore;
    scoreCount++;
  }

  // Dynamic categorization by account
  if (!stats.byAccount[account]) stats.byAccount[account] = 0;
  stats.byAccount[account]++;

  // Stream categorization
  if (myAccountTagSet.has(account)) {
    stats.byStream.myAccounts++;
  } else if (tweet.nicheRelevanceScore || tweet['Niche Relevance Score']) {
    stats.byStream.viral++;
  } else {
    stats.byStream.trackedAccounts++;
  }

  if (compositeScore > stats.highestScore) {
    stats.highestScore = compositeScore;
    stats.topTweet = {
      account,
      text: (tweet.Text || tweet.text || '').substring(0, 60) + '...',
      score: compositeScore,
      views
    };
  }
});

stats.avgCompositeScore = scoreCount > 0 ? (scoreSum / scoreCount).toFixed(1) : 0;

const formatNumber = (num) => num.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ',');

// Build dynamic breakdown
const breakdownLines = Object.entries(stats.byAccount)
  .sort((a, b) => b[1] - a[1])
  .map(([account, count]) => `  * ${account}: ${count}`)
  .join('\n');

const message = `\u{1F389} *X Research Complete*

\u{1F4CA} *Summary*
\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}\u{2501}
\u{2705} Total: *${formatNumber(stats.totalTweets)}* tweets

\u{1F4C1} *By Stream:*
\u{2022} My Accounts: ${stats.byStream.myAccounts}
\u{2022} Tracked Accounts: ${stats.byStream.trackedAccounts}
\u{2022} Viral: ${stats.byStream.viral}

\u{1F464} *By Account:*
${breakdownLines}

\u{1F4C8} *Metrics:*
\u{2022} Views: ${formatNumber(stats.totalViews)}
\u{2022} Engagement: ${formatNumber(stats.totalEngagement)}
\u{2022} Bookmarks: ${formatNumber(stats.totalBookmarks)}
\u{2022} Avg Score: ${stats.avgCompositeScore}/100

\u{1F3C6} *Top Tweet (Score: ${stats.highestScore}):*
${stats.topTweet ? `${stats.topTweet.account}\n"${stats.topTweet.text}"` : 'N/A'}

\u{23F0} ${new Date().toLocaleString('en-US', { timeZone: 'America/New_York', dateStyle: 'short', timeStyle: 'short' })}`;

return { json: { text: message } };

// ============================================
// SESSION CONFIG - FULLY DYNAMIC VERSION
// ============================================
// All accounts, search terms, and tracked accounts
// are pulled from Airtable. No hardcoded names.
// ============================================

const now = new Date();
const inputData = $input.all();

// ============================================
// EXTRACT MY ACCOUNTS FROM myAccounts TABLE
// ============================================
const myAccountsData = inputData.filter(item =>
  item.json.Voice && item.json.Username && item.json.Active
);

// Build dynamic array of all my accounts - NO hardcoding
// AccountTag comes from Airtable (e.g., "nozTweets", "wwTweets", "jbTweets")
const myAccounts = myAccountsData.map(a => ({
  username: a.json.Username,
  voice: a.json.Voice,
  accountTag: a.json.accountTag || a.json.AccountTag || a.json['Account Tag'] || (a.json.Voice.replace(/\s+/g, '') + 'Tweets')
}));

const myAccountUsernames = myAccounts.map(a => a.username);

console.log('=== MY ACCOUNTS (DYNAMIC) ===');
console.log('Count:', myAccounts.length);
console.log('Accounts:', JSON.stringify(myAccounts));

// ============================================
// EXTRACT SEARCH TERMS FROM searchTerms TABLE
// ============================================
const searchTermsData = inputData.filter(item =>
  item.json.Term && item.json.Tier && item.json.Active
);

const tierContext = inputData.find(item => item.json.termTier)?.json.termTier || 'primary';
const allowedTiers = tierContext.split(',');

console.log('=== SEARCH TERMS ===');
console.log('Tier Context:', tierContext);
console.log('Allowed Tiers:', allowedTiers);

const filteredTerms = searchTermsData.filter(item =>
  allowedTiers.includes(item.json.Tier)
);

const searchTermsWithMeta = filteredTerms.map(item => ({
  term: item.json.Term,
  tier: item.json.Tier,
  intent: item.json.Intent,
  category: item.json.Category
}));

const viralSearchTerms = searchTermsWithMeta.map(t => t.term);

console.log('Filtered Terms Count:', viralSearchTerms.length);
console.log('Terms by Tier:', {
  primary: filteredTerms.filter(t => t.json.Tier === 'primary').length,
  secondary: filteredTerms.filter(t => t.json.Tier === 'secondary').length,
  rotating: filteredTerms.filter(t => t.json.Tier === 'rotating').length
});

// ============================================
// EXTRACT TRACKED ACCOUNTS FROM trackedAccounts TABLE
// ============================================
const trackedAccountsData = inputData.filter(item =>
  item.json.Username &&
  item.json.Priority &&
  item.json.Active &&
  !item.json.Voice
);

const trackedAccounts = trackedAccountsData.map(item => item.json.Username);

const trackedAccountsWithMeta = trackedAccountsData.map(item => ({
  username: item.json.Username,
  category: item.json.Category,
  voiceAlignment: item.json['Voice Alignment'],
  priority: item.json.Priority,
  focus: item.json.Focus || ''
}));

console.log('=== TRACKED ACCOUNTS ===');
console.log('Tracked Accounts Count:', trackedAccounts.length);
console.log('First 10:', trackedAccounts.slice(0, 10));

// ============================================
// TIME RANGE CALCULATION
// ============================================
const collectedAtData = inputData.find(item => item.json['Collected At']);

let startTime = new Date(now);
startTime.setDate(startTime.getDate() - 7);

if (collectedAtData?.json['Collected At']) {
  const lastCollected = new Date(collectedAtData.json['Collected At']);
  startTime = new Date(lastCollected);
  startTime.setDate(startTime.getDate() - 7);
}

// Pad month/day to 2 digits for consistent date format
const formatDate = (date) => {
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, '0');
  const d = String(date.getDate()).padStart(2, '0');
  return `${y}-${m}-${d}`;
};

console.log('=== TIME RANGE ===');
console.log('Start Time:', formatDate(startTime));
console.log('End Time:', formatDate(now));

// ============================================
// OUTPUT - FULLY DYNAMIC
// ============================================
return {
  json: {
    myAccounts,
    myAccountUsernames,
    trackedAccounts,
    trackedAccountsWithMeta,
    viralSearchTerms,
    searchTermsWithMeta,
    tierContext,
    startTime: formatDate(startTime),
    endTime: formatDate(now),
    sessionId: `x_research_${Date.now()}`
  }
};
